package com.travelassistant.consultation;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;
@Entity @Table(name="conversation_message_requests",uniqueConstraints=@UniqueConstraint(columnNames={"conversation_id","operation","idempotency_key"}))public class MessageRequest{@Id @Column(length=36)private String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="conversation_id")private Conversation conversation;@Column(nullable=false,length=32)private String operation;@Column(name="idempotency_key",nullable=false,length=128)private String key;@Column(name="request_hash",nullable=false,length=64)private String hash;@OneToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="user_message_id")private Message userMessage;@OneToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="assistant_message_id")private Message assistantMessage;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;protected MessageRequest(){}public MessageRequest(Conversation c,String op,String key,String hash,Message u,Message a){conversation=c;operation=op;this.key=key;this.hash=hash;userMessage=u;assistantMessage=a;}@PrePersist void init(){id=UUID.randomUUID().toString();createdAt=Instant.now();}public String getHash(){return hash;}public Message getUserMessage(){return userMessage;}public Message getAssistantMessage(){return assistantMessage;}}
